const projectScripts = {
  'data:text/javascript;base64,': 'board_js',
  'data:text/javascript;base64,' : 'ray',
  'data:text/javascript;base64,' : 'base64',
  'data:@file/octet-stream;base64,':'hls',
  'data:@file/octet-stream;base64,':'jszip',
  'data:text/javascript;base64,' : 'play'
//start adding here
};

// Ensure projectScripts is defined as a standard Object
var keys = Object.keys(projectScripts); 

for (var i = 0; i < keys.length; i++) {
    var base64Src = keys[i];            // This is your URL/Base64 string
    var targetId = projectScripts[base64Src]; // This is your ID
    
    if (document.getElementById(targetId)) {
        var s = document.createElement('script');
        s.src = base64Src;
        document.head.appendChild(s);
    }
}
